import{_ as t,X as s,Y as r,Z as e,$ as a,a1 as o,a0 as i,H as d}from"./framework-4f44829b.js";const l={},h=e("h1",{id:"分布式",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#分布式","aria-hidden":"true"},"#"),a(" 分布式")],-1),c={href:"https://zq99299.github.io/note-architect/hc/",target:"_blank",rel:"noopener noreferrer"},p={href:"https://dunwu.github.io/db-tutorial/#%F0%9F%93%96-%E5%86%85%E5%AE%B9",target:"_blank",rel:"noopener noreferrer"},u=i(`<h2 id="一致性算法" tabindex="-1"><a class="header-anchor" href="#一致性算法" aria-hidden="true">#</a> 一致性算法</h2><h2 id="全局唯一id" tabindex="-1"><a class="header-anchor" href="#全局唯一id" aria-hidden="true">#</a> 全局唯一ID</h2><h2 id="分布式锁" tabindex="-1"><a class="header-anchor" href="#分布式锁" aria-hidden="true">#</a> 分布式锁</h2><h3 id="概述" tabindex="-1"><a class="header-anchor" href="#概述" aria-hidden="true">#</a> 概述</h3><p>主要思路：</p><ol><li><strong>互斥、可重入</strong></li></ol><blockquote><p>​ 创建锁必须是唯一的，表现形式为向数据存储服务器或容器插入一个唯一的 key，一旦有一个线程插入这个 key，其他线程就不能再插入了。</p></blockquote><ol start="2"><li><strong>避免死锁</strong></li></ol><blockquote><p>​ 数据库分布式锁和缓存分布式锁（Redis）的思路都是引入超时机制，即成功申请锁后，超过一定时间，锁失效（删除 key），原因在于它们无法感知申请锁的客户端节点状态。而 ZooKeeper 由于其 znode 以目录、文件形式组织，天然就存在物理空间隔离，只要 znode 存在，即表示客户端节点还在工作，所以不存在这种问题。</p></blockquote><ol start="3"><li><strong>容错</strong></li></ol><blockquote><p>​ 只要大部分 Redis 节点可用，客户端就能正常加锁。</p></blockquote><ol start="4"><li><strong>自旋重试</strong></li></ol><blockquote><p>​ 获取不到锁时，不要直接返回失败，而是支持一定的周期自旋重试，设置一个总的超时时间，当过了超时时间以后还没有获取到锁则返回失败。</p></blockquote><hr><h3 id="数据库锁" tabindex="-1"><a class="header-anchor" href="#数据库锁" aria-hidden="true">#</a> 数据库锁</h3><p>可以使用行锁作为分布式锁</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">select</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> <span class="token keyword">from</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> <span class="token keyword">for</span> <span class="token keyword">update</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>优点：</p><blockquote><ol><li>直接借助数据库，容易理解，方便使用。</li><li>可阻塞，别的线程可以进行等待获取。</li></ol></blockquote><p>缺点：</p><blockquote><ol><li>强依赖数据库的可用性。如果数据库是一个单点，一旦数据库挂掉，会导致业务系统不可用。</li><li>没有失效时间，一旦解锁操作失败，就会导致锁记录一直在数据库中，其他线程无法再获得到锁。</li><li>非重入的，同一个线程在没有释放锁之前无法再次获得该锁。因为行锁已经被占有。</li></ol></blockquote><hr><h3 id="redis锁" tabindex="-1"><a class="header-anchor" href="#redis锁" aria-hidden="true">#</a> Redis锁</h3><h4 id="setnx" tabindex="-1"><a class="header-anchor" href="#setnx" aria-hidden="true">#</a> setnx</h4><h4 id="redlock" tabindex="-1"><a class="header-anchor" href="#redlock" aria-hidden="true">#</a> RedLock</h4><h3 id="zookeeper锁" tabindex="-1"><a class="header-anchor" href="#zookeeper锁" aria-hidden="true">#</a> zookeeper锁</h3><h2 id="分布式事务" tabindex="-1"><a class="header-anchor" href="#分布式事务" aria-hidden="true">#</a> 分布式事务</h2><h2 id="分布式缓存" tabindex="-1"><a class="header-anchor" href="#分布式缓存" aria-hidden="true">#</a> 分布式缓存</h2><h2 id="分布式session" tabindex="-1"><a class="header-anchor" href="#分布式session" aria-hidden="true">#</a> 分布式Session</h2>`,29);function k(b,_){const n=d("ExternalLinkIcon");return s(),r("div",null,[h,e("p",null,[e("a",c,[a("https://zq99299.github.io/note-architect/hc/"),o(n)])]),e("p",null,[e("a",p,[a("https://dunwu.github.io/db-tutorial/#📖-内容"),o(n)])]),u])}const x=t(l,[["render",k],["__file","分布式.html.vue"]]);export{x as default};
